PLATFORMIO_MAIN_CPP_TEMPLATE = '''// HubEx — Device Firmware (PlatformIO / Arduino framework)
// Board: {board_name}
// Auto-generated — safe to edit.

#include <Arduino.h>
#include <WiFi.h>
#include <HTTPClient.h>
#include <ArduinoJson.h>
#include "config.h"

{library_includes}

{pin_defines}
{sensor_init}

const unsigned long READ_INTERVAL_MS = {read_interval};
unsigned long lastRead = 0;

void connectWifi() {{
  Serial.print("[HUBEX] Connecting to ");
  Serial.println(HUBEX_WIFI_SSID);
  WiFi.begin(HUBEX_WIFI_SSID, HUBEX_WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) {{
    delay(500);
    Serial.print(".");
  }}
  Serial.println();
  Serial.print("[HUBEX] WiFi OK, ip=");
  Serial.println(WiFi.localIP());
}}

void pushTelemetry() {{
  if (WiFi.status() != WL_CONNECTED) {{
    connectWifi();
  }}
  HTTPClient http;
  http.begin(String(HUBEX_SERVER_URL) + "/api/v1/telemetry");
  http.addHeader("X-Device-Token", HUBEX_DEVICE_TOKEN);
  http.addHeader("Content-Type", "application/json");

  JsonDocument doc;
  doc["event_type"] = "sensor_reading";
  JsonObject payload = doc["payload"].to<JsonObject>();
{telemetry_fields}

  String json;
  serializeJson(doc, json);
  int code = http.POST(json);
  Serial.printf("[HUBEX] telemetry -> %d\\n", code);
  http.end();
}}

void setup() {{
  Serial.begin(115200);
  delay(200);
  Serial.println("[HUBEX] Booting " HUBEX_DEVICE);

  {pin_setup}
  {sensor_setup}

  connectWifi();
}}

void loop() {{
  if (millis() - lastRead >= READ_INTERVAL_MS) {{
    lastRead = millis();
{sensor_read}
    pushTelemetry();
  }}
  delay(10);
}}
'''


