MICROPYTHON_BOOT_PY_TEMPLATE = '''# HubEx — boot.py (runs once on device boot)
# Connects to WiFi so main.py can push telemetry.

import network
import time
from config import WIFI_SSID, WIFI_PASS

def _connect():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("[HUBEX] connecting to", WIFI_SSID)
        wlan.connect(WIFI_SSID, WIFI_PASS)
        for _ in range(30):
            if wlan.isconnected():
                break
            time.sleep(0.5)
    if wlan.isconnected():
        print("[HUBEX] wifi ok:", wlan.ifconfig())
    else:
        print("[HUBEX] wifi FAILED")

_connect()
'''


MICROPYTHON_MAIN_PY_TEMPLATE = '''# HubEx — main.py (MicroPython firmware)
# Board: {board_name}
# Auto-generated by HubEx Code Generator.

import time
try:
    import urequests as requests
except ImportError:
    import requests

from machine import Pin
from config import SERVER_URL, DEVICE_TOKEN

{mpy_imports}

READ_INTERVAL_S = {read_interval_s}

# ── Pin setup ──────────────────────────────────────────────────────────
{mpy_pin_setup}

# ── Sensor init ────────────────────────────────────────────────────────
{mpy_sensor_init}


def read_sensors():
    """Return a dict of variable_key -> value."""
    payload = {{}}
{mpy_sensor_read}
    return payload


def push_telemetry(payload):
    try:
        r = requests.post(
            SERVER_URL + "/api/v1/telemetry",
            headers={{
                "X-Device-Token": DEVICE_TOKEN,
                "Content-Type": "application/json",
            }},
            json={{"event_type": "sensor_reading", "payload": payload}},
        )
        print("[HUBEX] telemetry ->", r.status_code)
        r.close()
    except Exception as e:
        print("[HUBEX] telemetry error:", e)


print("[HUBEX] main loop started")
while True:
    push_telemetry(read_sensors())
    time.sleep(READ_INTERVAL_S)
'''


